from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Annotated

import anyio
from fastapi import Depends

from app.core.config import Settings, get_settings
from app.services.patcher.atomic import atomic_write_text
from app.services.patcher.git import commit_all, head_sha
from app.services.patcher.ops import HUMAN_NOTES_HEADING, PatchOperationError

MAX_BYTES = 32_768


class HumanNotesError(ValueError):
    """Raised when human-notes content fails validation or the file lacks a boundary."""


@dataclass(frozen=True)
class HumanNotesWriteResult:
    rel_path: str
    bytes_written: int
    commit_sha: str | None


def split_at_boundary(content: str) -> tuple[str, str]:
    if content.startswith(HUMAN_NOTES_HEADING):
        return "", content
    marker = f"\n{HUMAN_NOTES_HEADING}"
    idx = content.find(marker)
    if idx == -1:
        raise PatchOperationError("missing # Human Notes boundary")
    return content[: idx + 1], content[idx + 1 :]


def replace_human_notes(content: str, body: str) -> str:
    above, _ = split_at_boundary(content)
    body_normalized = _normalize_body(body)
    if body_normalized:
        return f"{above}{HUMAN_NOTES_HEADING}\n\n{body_normalized}"
    return f"{above}{HUMAN_NOTES_HEADING}\n"


def _normalize_body(body: str) -> str:
    stripped = body.replace("\r\n", "\n").strip()
    if not stripped:
        return ""
    return stripped + "\n"


def validate_body(body: str) -> None:
    encoded = body.encode("utf-8")
    if len(encoded) > MAX_BYTES:
        raise HumanNotesError(f"human notes exceed {MAX_BYTES} bytes")
    if HUMAN_NOTES_HEADING in body:
        raise HumanNotesError("human notes body must not contain another '# Human Notes' heading")


class HumanNotesService:
    def __init__(self, *, wiki_dir: Path) -> None:
        self._wiki_dir = wiki_dir

    def _resolve_safe(self, rel_path: str) -> Path:
        if not rel_path or rel_path.startswith("/") or ".." in Path(rel_path).parts:
            raise HumanNotesError("invalid path")
        if not rel_path.endswith(".md"):
            raise HumanNotesError("path must reference a markdown file")
        full = (self._wiki_dir / rel_path).resolve()
        root = self._wiki_dir.resolve()
        if root not in full.parents:
            raise HumanNotesError("path escapes wiki_dir")
        return full

    async def read(self, rel_path: str) -> str | None:
        full = self._resolve_safe(rel_path)
        if not await anyio.Path(full).is_file():
            return None
        content = await anyio.Path(full).read_text(encoding="utf-8")
        try:
            _, below = split_at_boundary(content)
        except PatchOperationError:
            return None
        body = below[len(HUMAN_NOTES_HEADING) :].lstrip("\n").rstrip()
        return body

    async def write(self, rel_path: str, *, body: str, pm_user: str) -> HumanNotesWriteResult:
        validate_body(body)
        full = self._resolve_safe(rel_path)
        if not await anyio.Path(full).is_file():
            raise HumanNotesError("file not found")
        existing = await anyio.Path(full).read_text(encoding="utf-8")
        try:
            updated = replace_human_notes(existing, body)
        except PatchOperationError as exc:
            raise HumanNotesError(str(exc)) from exc
        if updated == existing:
            return HumanNotesWriteResult(
                rel_path=rel_path,
                bytes_written=0,
                commit_sha=head_sha(self._wiki_dir),
            )
        atomic_write_text(full, updated)
        diff = commit_all(
            self._wiki_dir,
            message=f"human-notes({rel_path}): {pm_user}",
        )
        return HumanNotesWriteResult(
            rel_path=rel_path,
            bytes_written=len(updated.encode("utf-8")),
            commit_sha=diff,
        )


def get_human_notes_service(
    settings: Annotated[Settings, Depends(get_settings)],
) -> HumanNotesService:
    return HumanNotesService(wiki_dir=settings.wiki_dir)

from __future__ import annotations

import re
from collections.abc import Mapping
from typing import Any

import yaml

HUMAN_NOTES_HEADING = "# Human Notes"

_HEADING_RE = re.compile(r"^(#{1,6})\s+(.+?)\s*$", re.MULTILINE)


class PatchOperationError(ValueError):
    """Raised when a patch operation cannot be applied safely."""


def split_human_notes(content: str) -> tuple[str, str]:
    """Return (managed, human) split. Human side is empty if no boundary present."""
    if content.startswith(HUMAN_NOTES_HEADING):
        return "", content
    marker = f"\n{HUMAN_NOTES_HEADING}"
    idx = content.find(marker)
    if idx == -1:
        return content, ""
    return content[: idx + 1], content[idx + 1 :]


def render_page(*, frontmatter: Mapping[str, Any] | None, body: str) -> str:
    """Render a page from optional frontmatter + body. Body is taken as-is."""
    body_norm = body.rstrip() + "\n" if body.strip() else ""
    if not frontmatter:
        return body_norm
    fm = yaml.safe_dump(dict(frontmatter), sort_keys=False, allow_unicode=True).strip()
    return f"---\n{fm}\n---\n\n{body_norm}"


def parse_frontmatter(content: str) -> tuple[dict[str, Any], str]:
    """Return (frontmatter, body). Empty dict if no frontmatter block."""
    if not content.startswith("---\n"):
        return {}, content
    end = content.find("\n---\n", 4)
    if end == -1:
        return {}, content
    raw = content[4:end]
    rest = content[end + 5 :]
    try:
        data = yaml.safe_load(raw) or {}
    except yaml.YAMLError:
        return {}, content
    if not isinstance(data, dict):
        return {}, content
    return data, rest.lstrip("\n")


def create_page(
    *,
    path_exists: bool,
    existing: str,
    frontmatter: Mapping[str, Any] | None,
    body: str,
) -> str:
    """Create a page if missing. If it exists, return existing unchanged (idempotent)."""
    if path_exists and existing.strip():
        return existing
    return render_page(frontmatter=frontmatter, body=body)


def upsert_section(content: str, *, heading: str, body: str) -> str:
    """Replace the body of `## {heading}`; append the section if absent.

    Refuses to write below `# Human Notes` if a boundary is present.
    """
    managed, human = split_human_notes(content)
    new_body = body.rstrip() + "\n" if body.strip() else "\n"

    section_re = re.compile(rf"^##\s+{re.escape(heading)}\s*$", re.MULTILINE)
    match = section_re.search(managed)
    if match is None:
        prefix = managed.rstrip()
        sep = "\n\n" if prefix else ""
        new_managed = f"{prefix}{sep}## {heading}\n\n{new_body}"
        return _join_managed_human(new_managed, human)

    start = match.end()
    next_match = _HEADING_RE.search(managed, pos=start)
    end = next_match.start() if next_match else len(managed)
    new_managed = managed[:start] + "\n\n" + new_body + managed[end:].lstrip("\n")
    if not new_managed.endswith("\n"):
        new_managed += "\n"
    return _join_managed_human(new_managed, human)


def append_section(content: str, *, heading: str, line: str) -> str:
    """Append a single line to `## {heading}`; create the section if absent."""
    managed, human = split_human_notes(content)
    line_norm = line.rstrip("\n") + "\n"

    section_re = re.compile(rf"^##\s+{re.escape(heading)}\s*$", re.MULTILINE)
    match = section_re.search(managed)
    if match is None:
        prefix = managed.rstrip()
        sep = "\n\n" if prefix else ""
        new_managed = f"{prefix}{sep}## {heading}\n\n{line_norm}"
        return _join_managed_human(new_managed, human)

    start = match.end()
    next_match = _HEADING_RE.search(managed, pos=start)
    end = next_match.start() if next_match else len(managed)
    section_body = managed[start:end]
    trimmed = section_body.rstrip("\n")
    new_section = trimmed + "\n" + line_norm
    if not new_section.startswith("\n"):
        new_section = "\n" + new_section
    new_managed = managed[:start] + new_section + managed[end:].lstrip("\n")
    if not new_managed.endswith("\n"):
        new_managed += "\n"
    return _join_managed_human(new_managed, human)


def prepend_log(content: str, *, line: str) -> str:
    """Prepend a single line to log.md, after any leading H1 + blank line."""
    line_norm = line.rstrip("\n") + "\n"
    if not content.strip():
        return line_norm

    # If file starts with a single H1 ("# Title"), insert below it.
    first_match = _HEADING_RE.match(content)
    if first_match and first_match.group(1) == "#":
        head_end = first_match.end()
        rest = content[head_end:]
        rest_lstripped = rest.lstrip("\n")
        return content[:head_end] + "\n\n" + line_norm + rest_lstripped

    return line_norm + content if content.endswith("\n") else line_norm + content + "\n"


def _join_managed_human(managed: str, human: str) -> str:
    if not human:
        return managed
    if not managed.endswith("\n"):
        managed += "\n"
    return managed + human

from __future__ import annotations

import re
from collections.abc import Sequence
from dataclasses import dataclass
from pathlib import Path

from app.schemas.patch_plan import (
    AppendSectionOp,
    CreatePageOp,
    PatchOp,
    PatchPlan,
    PrependLogOp,
    UpsertSectionOp,
)
from app.services.patcher.atomic import atomic_write_text
from app.services.patcher.git import commit_all, head_sha
from app.services.patcher.ops import (
    PatchOperationError,
    append_section,
    create_page,
    prepend_log,
    render_page,
    upsert_section,
)
from app.services.patcher.paths import property_file_path

_PROPERTY_ID_RE = re.compile(r"^[A-Z]+-\d+$")
_LOG_PATH = "log.md"


@dataclass(frozen=True)
class PatchApplyResult:
    event_id: str
    applied_ops: int
    commit_sha: str | None
    touched: tuple[str, ...]
    idempotent: bool = False
    skipped_ops: int = 0
    op_kinds: tuple[str, ...] = ()


def apply_patch_plan(plan: PatchPlan, *, wiki_dir: Path) -> PatchApplyResult:
    if _PROPERTY_ID_RE.fullmatch(plan.property_id) is None:
        raise ValueError(f"invalid property_id: {plan.property_id!r}")

    property_root = wiki_dir / plan.property_id
    property_root.mkdir(parents=True, exist_ok=True)

    touched: list[Path] = []
    unique_touched: list[Path] = []
    seen: set[Path] = set()
    skipped = 0
    op_kinds: list[str] = []
    for op in plan.ops:
        op_kinds.append(type(op).__name__)
        path = _apply_one(property_root, op)
        if path is None:
            skipped += 1
            continue
        touched.append(path)
        if path not in seen:
            seen.add(path)
            unique_touched.append(path)

    summary = plan.summary.strip() or plan.event_type
    commit_sha = commit_all(wiki_dir, message=f"ingest({plan.event_id}): {summary}".strip())
    rels = tuple(_relative_posix(p, property_root) for p in unique_touched)
    return PatchApplyResult(
        event_id=plan.event_id,
        applied_ops=len(touched),
        commit_sha=commit_sha,
        touched=rels,
        skipped_ops=skipped,
        op_kinds=tuple(op_kinds),
    )


def head_commit(wiki_dir: Path) -> str | None:
    return head_sha(wiki_dir)


def _apply_one(property_root: Path, op: PatchOp) -> Path | None:
    if isinstance(op, CreatePageOp):
        return _do_create_page(property_root, op)
    if isinstance(op, UpsertSectionOp):
        return _do_upsert_section(property_root, op)
    if isinstance(op, AppendSectionOp):
        return _do_append_section(property_root, op)
    if isinstance(op, PrependLogOp):
        return _do_prepend_log(property_root, op)
    raise PatchOperationError(f"unknown op: {op!r}")


def _do_create_page(property_root: Path, op: CreatePageOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    new_content = create_page(
        path_exists=file_path.is_file(),
        existing=existing,
        frontmatter=op.frontmatter,
        body=op.body,
    )
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _do_upsert_section(property_root: Path, op: UpsertSectionOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    base = existing or render_page(frontmatter=None, body="")
    new_content = upsert_section(base, heading=op.heading, body=op.body)
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _do_append_section(property_root: Path, op: AppendSectionOp) -> Path | None:
    file_path = property_file_path(property_root, op.path)
    _require_md(file_path)
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else ""
    base = existing or render_page(frontmatter=None, body="")
    new_content = append_section(base, heading=op.heading, line=op.line)
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _do_prepend_log(property_root: Path, op: PrependLogOp) -> Path | None:
    file_path = property_root / _LOG_PATH
    existing = file_path.read_text(encoding="utf-8") if file_path.is_file() else "# Log\n\n"
    new_content = prepend_log(existing, line=op.line)
    if new_content == existing:
        return None
    atomic_write_text(file_path, new_content)
    return file_path


def _require_md(path: Path) -> None:
    if path.suffix != ".md":
        raise PatchOperationError(f"path must be a markdown file: {path.name}")


def _relative_posix(path: Path, root: Path) -> str:
    try:
        return path.relative_to(root).as_posix()
    except ValueError:
        return path.name


def touched_for_reindex(touched: Sequence[str]) -> list[str]:
    return [t for t in touched if t.endswith(".md") and not t.startswith("_")]

from __future__ import annotations

from typing import Annotated, Literal

from fastapi import APIRouter, Depends, Header, HTTPException, Query, status
from fastapi.responses import PlainTextResponse
from pydantic import BaseModel, StringConstraints

from app.schemas.human_notes import (
    HumanNotesReadResponse,
    HumanNotesWriteRequest,
    HumanNotesWriteResponse,
)
from app.schemas.properties import PropertyId
from app.services.human_notes import (
    HumanNotesError,
    HumanNotesService,
    get_human_notes_service,
)
from app.services.wiki import TreeNode, WikiService, get_wiki_service

router = APIRouter()

RelPath = Annotated[
    str,
    StringConstraints(pattern=r"^[A-Za-z0-9._/-]+$", min_length=1, max_length=512),
]


class TreeNodeOut(BaseModel):
    name: str
    path: str
    type: Literal["file", "dir"]
    children: list[TreeNodeOut] | None = None


def _to_out(node: TreeNode) -> TreeNodeOut:
    return TreeNodeOut(
        name=node.name,
        path=node.path,
        type=node.type,
        children=[_to_out(c) for c in node.children] if node.children is not None else None,
    )


@router.get("/properties")
async def list_wiki_properties(
    service: Annotated[WikiService, Depends(get_wiki_service)],
) -> list[str]:
    return service.list_properties()


@router.get("/tree")
async def get_tree(
    lie: Annotated[PropertyId, Query(description="Property id, e.g. LIE-001")],
    service: Annotated[WikiService, Depends(get_wiki_service)],
) -> TreeNodeOut:
    node = service.walk_tree(lie)
    if node is None:
        raise HTTPException(status.HTTP_404_NOT_FOUND, f"property {lie!r} not found")
    return _to_out(node)


@router.get(
    "/file",
    response_class=PlainTextResponse,
    responses={200: {"content": {"text/markdown": {}}}},
)
async def get_file(
    path: Annotated[RelPath, Query(description="Path relative to wiki_dir")],
    service: Annotated[WikiService, Depends(get_wiki_service)],
) -> PlainTextResponse:
    try:
        content = await service.read_file(path)
    except ValueError as exc:
        raise HTTPException(status.HTTP_400_BAD_REQUEST, str(exc)) from exc
    if content is None:
        raise HTTPException(status.HTTP_404_NOT_FOUND, f"file {path!r} not found")
    return PlainTextResponse(content=content, media_type="text/markdown; charset=utf-8")


@router.get("/human-notes")
async def get_human_notes(
    path: Annotated[RelPath, Query(description="Path relative to wiki_dir")],
    service: Annotated[HumanNotesService, Depends(get_human_notes_service)],
) -> HumanNotesReadResponse:
    try:
        body = await service.read(path)
    except HumanNotesError as exc:
        raise HTTPException(status.HTTP_400_BAD_REQUEST, str(exc)) from exc
    if body is None:
        raise HTTPException(status.HTTP_404_NOT_FOUND, f"file {path!r} not found")
    return HumanNotesReadResponse(path=path, body=body)


@router.put("/human-notes")
async def put_human_notes(
    payload: HumanNotesWriteRequest,
    path: Annotated[RelPath, Query(description="Path relative to wiki_dir")],
    service: Annotated[HumanNotesService, Depends(get_human_notes_service)],
    pm_user: Annotated[str, Header(alias="x-pm-user", min_length=1, max_length=128)],
) -> HumanNotesWriteResponse:
    try:
        result = await service.write(path, body=payload.body, pm_user=pm_user)
    except HumanNotesError as exc:
        raise HTTPException(status.HTTP_400_BAD_REQUEST, str(exc)) from exc
    return HumanNotesWriteResponse(
        path=result.rel_path,
        bytes_written=result.bytes_written,
        commit_sha=result.commit_sha,
    )

from __future__ import annotations

import subprocess
from pathlib import Path


def run_git(args: list[str], cwd: Path, *, check: bool = True) -> subprocess.CompletedProcess[str]:
    return subprocess.run(  # noqa: S603
        ["git", *args],  # noqa: S607
        cwd=cwd,
        check=check,
        capture_output=True,
        text=True,
    )


def commit_all(wiki_dir: Path, *, message: str) -> str | None:
    run_git(["add", "-A"], cwd=wiki_dir)
    diff = run_git(["diff", "--cached", "--quiet"], cwd=wiki_dir, check=False)
    if diff.returncode == 0:
        return head_sha(wiki_dir)
    if diff.returncode != 1:
        raise subprocess.CalledProcessError(diff.returncode, diff.args, diff.stdout, diff.stderr)
    run_git(["commit", "-m", message], cwd=wiki_dir)
    return head_sha(wiki_dir)


def head_sha(wiki_dir: Path) -> str | None:
    result = run_git(["rev-parse", "HEAD"], cwd=wiki_dir, check=False)
    if result.returncode != 0:
        return None
    return result.stdout.strip()

from __future__ import annotations

from pathlib import Path, PurePosixPath


def normalize_property_file(path: str, *, property_id: str) -> str:
    """Return a property-relative posix path; reject anything that escapes."""
    pure = PurePosixPath(path.replace("\\", "/"))
    if pure.is_absolute():
        raise ValueError("patch file path must be relative")

    parts = list(pure.parts)
    if parts and parts[0] == "wiki":
        parts = parts[1:]
    if parts and parts[0] == property_id:
        parts = parts[1:]

    if not parts:
        raise ValueError("patch file path must include a filename")
    if any(part in {"", ".", ".."} for part in parts):
        raise ValueError("patch file path must stay inside the property")
    return PurePosixPath(*parts).as_posix()


def property_file_path(property_root: Path, path: str) -> Path:
    relative = normalize_property_file(path, property_id=property_root.name)
    root = property_root.resolve(strict=False)
    candidate = property_root / relative
    resolved = candidate.resolve(strict=False)
    if resolved != root and root not in resolved.parents:
        raise ValueError("patch file path escapes the property")
    return candidate

from __future__ import annotations

import re
from collections.abc import Sequence
from dataclasses import dataclass
from pathlib import Path

from app.storage.wiki_chunks import open_wiki_chunks

_ENTITY_REF_RE = re.compile(r"\b(?:LIE|HAUS|EH|EIG|MIE|DL|INV|LTR|EMAIL|TX)-[A-Z]*-?\d{2,6}\b")


@dataclass(frozen=True)
class IndexedSection:
    file: str
    section: str
    body: str
    entity_refs: list[str]


def reindex_files(
    *,
    wiki_dir: Path,
    property_id: str,
    files: Sequence[Path | str],
    db_path: Path,
) -> int:
    store = open_wiki_chunks(db_path)
    property_root = wiki_dir / property_id
    count = 0
    for file in files:
        relative = Path(file)
        if relative.is_absolute():
            try:
                relative = relative.relative_to(property_root)
            except ValueError:
                continue
        if relative.suffix != ".md":
            continue
        store.delete_file(property_id, relative.as_posix())
        path = property_root / relative
        if not path.is_file():
            continue
        content = path.read_text(encoding="utf-8")
        for section in parse_markdown_sections(content, relative.as_posix()):
            store.upsert(
                property_id,
                section.file,
                section.section,
                section.body,
                section.entity_refs,
            )
            count += 1
    store.build_index()
    return count


def reindex_property(*, wiki_dir: Path, property_id: str, db_path: Path) -> int:
    property_root = wiki_dir / property_id
    files = [path.relative_to(property_root) for path in property_root.rglob("*.md")]
    return reindex_files(wiki_dir=wiki_dir, property_id=property_id, files=files, db_path=db_path)


def parse_markdown_sections(content: str, file: str) -> list[IndexedSection]:
    body = _strip_frontmatter(content)
    managed = body.split("\n# Human Notes", 1)[0]
    matches = list(re.finditer(r"^## (?P<section>.+?)\s*$", managed, flags=re.MULTILINE))
    sections: list[IndexedSection] = []
    if not matches and managed.strip():
        sections.append(
            IndexedSection(
                file=file,
                section="(body)",
                body=managed.strip(),
                entity_refs=_entity_refs(managed),
            )
        )
        return sections
    for idx, match in enumerate(matches):
        start = match.end()
        end = matches[idx + 1].start() if idx + 1 < len(matches) else len(managed)
        section_body = managed[start:end].strip()
        section_name = match.group("section").strip()
        sections.append(
            IndexedSection(
                file=file,
                section=section_name,
                body=section_body,
                entity_refs=_entity_refs(f"{section_name}\n{section_body}"),
            )
        )
    return sections


def _strip_frontmatter(content: str) -> str:
    if not content.startswith("---\n"):
        return content
    end = content.find("\n---\n", 4)
    if end == -1:
        return content
    return content[end + 5 :].lstrip("\n")


def _entity_refs(text: str) -> list[str]:
    seen: set[str] = set()
    refs: list[str] = []
    for match in _ENTITY_REF_RE.finditer(text):
        ref = match.group(0).upper()
        if ref in seen:
            continue
        seen.add(ref)
        refs.append(ref)
    return refs

