from __future__ import annotations

from pathlib import Path

from app.services.patcher.atomic import atomic_write_text

BASELINE_DIR = ".agent-base"


def baseline_path(wiki_dir: Path, *, property_id: str, rel_path: str) -> Path:
    return wiki_dir / BASELINE_DIR / property_id / rel_path


def read_baseline(wiki_dir: Path, *, property_id: str, rel_path: str) -> str | None:
    path = baseline_path(wiki_dir, property_id=property_id, rel_path=rel_path)
    if not path.is_file():
        return None
    return path.read_text(encoding="utf-8")


def write_baseline(
    wiki_dir: Path,
    *,
    property_id: str,
    rel_path: str,
    content: str,
) -> None:
    path = baseline_path(wiki_dir, property_id=property_id, rel_path=rel_path)
    atomic_write_text(path, content)


def ensure_gitignore(wiki_dir: Path) -> None:
    """Make sure .agent-base/ is excluded from the wiki repo."""
