        await anyio.Path(full).read_text(encoding="utf-8")
        if await anyio.Path(full).is_file()
        else None
    )
    if existing == normalized:
        return 0, head_sha(self._wiki_dir)
    atomic_write_text(full, normalized)
    sha = commit_all(self._wiki_dir, message=f"user-edit({rel_path}): {pm_user}")
